class Solution:
    def isMatch(self, s, p):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(i, j):
            if j == len(p):
                return i == len(s)
            if p[j] == '*':
                return dp(i, j + 1) or (i < len(s) and dp(i + 1, j))
            if i < len(s) and (p[j] == '?' or p[j] == s[i]):
                return dp(i + 1, j + 1)
            return False
        return dp(0, 0)

